-- prepare_and_access rotational power slots
INSERT INTO coaching.phase_order_slot (key, name, description, phase_id, order_index, freshness_sensitivity, subrole_key)
SELECT v.key, v.name, v.description, sp.id, v.order_index, v.freshness_sensitivity, v.subrole_key
FROM coaching.session_phase sp
CROSS JOIN (VALUES
  ('hip_rotation_9090_reach_access', 'Hip Rotation 9090 Reach Access', 'Hip rotation access — 90/90 Hip Switch with Reach.', 149, 2, 'mobilize'),
  ('half_kneeling_t_spine_rotation_access', 'Half Kneeling T Spine Rotation Access', 'Thoracic rotation access — Half-Kneeling T-Spine Rotation.', 150, 2, 'mobilize'),
  ('spiderman_lunge_t_spine_reach', 'Spiderman Lunge T Spine Reach', 'Lunge rotation mobility — Spiderman Lunge with T-Spine Reach.', 151, 2, 'mobilize'),
  ('wall_split_stance_rotation_reach', 'Wall Split Stance Rotation Reach', 'Split-stance rotation access — Wall Split-Stance Rotation Reach.', 152, 2, 'mobilize'),
  ('quadruped_thread_the_needle_reach', 'Quadruped Thread The Needle Reach', 'Ground-based thoracic rotation — Quadruped Thread-the-Needle Reach.', 153, 2, 'mobilize'),
  ('lateral_lunge_reach_across', 'Lateral Lunge Reach Across', 'Frontal-plane access — Lateral Lunge with Reach Across.', 154, 2, 'mobilize'),
  ('cossack_shift_t_spine_reach', 'Cossack Shift T Spine Reach', 'Deep lateral rotation access — Cossack Shift with T-Spine Reach.', 155, 2, 'mobilize'),
  ('band_resisted_hip_turn_drill', 'Band Resisted Hip Turn Drill', 'Hip turn activation — Band-Resisted Hip Turn Drill.', 156, 2, 'activate'),
  ('low_intensity_carioca_grapevine', 'Low Intensity Carioca Grapevine', 'Rotational locomotion integration — Low-Intensity Carioca / Grapevine.', 157, 2, 'integrate')
) AS v(key, name, description, order_index, freshness_sensitivity, subrole_key)
WHERE sp.key = 'prepare_and_access'
ON CONFLICT (key) DO UPDATE SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  phase_id = EXCLUDED.phase_id,
  order_index = EXCLUDED.order_index,
  freshness_sensitivity = EXCLUDED.freshness_sensitivity,
  subrole_key = EXCLUDED.subrole_key;

