-- Insert 38 new rotational power exercises
INSERT INTO coaching.exercise (
  facility_id, name, slug, description, sport_id, skill_level, age_min,
  default_sets, default_reps, default_work_seconds, default_rest_seconds, est_seconds_per_set,
  is_published, visibility,
  card_summary, coach_language, athlete_language,
  movement_family, primary_phase_key, phase_subrole, primary_order_slot,
  movement_requirements, coaching_execution
)
SELECT
  f.id,
  d.name, d.slug, d.description,
  (SELECT id FROM coaching.sport WHERE key = 'fitness'),
  d.skill::public.skill_level,
  d.age_min,
  d.sets, d.reps, d.work, d.rest, d.est,
  TRUE, 'facility',
  d.summary, d.coach_lang, d.athlete_lang,
  d.family, d.phase_key, d.subrole, d.slot,
  d.req::jsonb, d.exec::jsonb
FROM (VALUES
  ('Half-Kneeling T-Spine Rotation', 'half-kneeling-t-spine-rotation', 'Perform Half-Kneeling T-Spine Rotation slowly enough to create usable rotational access and coordination. Move through pain-free range, breathe, and own the position before adding speed or load.', 'BEGINNER', 8, 2, 6, 25, 20, 45, 'Half-Kneeling T-Spine Rotation is a Prepare & Access exercise for thoracic rotation with pelvis anchored. Use it when the goal is rotational skill, force transfer, or power quality rather than fatigue chasing.', 'Primary subrole: mobilize. Coach Half-Kneeling T-Spine Rotation as rotational-athlete work: rotation should be organized through feet, hips, pelvis, thoracic spine, shoulders, and the implement or direction change - not forced through the low back.', 'Open the range, feel the turn, and do not force your low back.', 'Thoracic rotation access', 'prepare_and_access', 'mobilize', 'half_kneeling_t_spine_rotation_access', '{"primary_joint_actions":["hip rotation","thoracic rotation","trunk bracing"],"primary_tissues":["core","hip","shoulder","spine"],"breathing_demand":"low_to_moderate","balance_demand":"moderate","coordination_demand":"moderate_to_high","impact_level":0,"rotational_power_profile":{"rotation_source":"feet, hips, pelvis, thoracic spine, and shoulders; avoid forced lumbar twisting","sequence_priority":"load or gather, brace, rotate, transfer, finish, and reset","quality_rule":"The rep counts only if the athlete keeps foot pressure, rib-pelvis organization, clean rotational path, safe finish, and a reset that could be repeated."}}'::jsonb, '{"movement_description":"Perform Half-Kneeling T-Spine Rotation slowly enough to create usable rotational access and coordination. Move through pain-free range, breathe, and own the position before adding speed or load.","setup":["Clear the training area and define the athlete''s start position, finish position, and stop command.","Coach one clean practice rep before adding load, speed, partner input, or decision demand."],"execution_steps":["Move into the starting position slowly and find the target joint or stance position.","Rotate, reach, shift, or step through pain-free range while breathing naturally.","Return with control and repeat only as long as the motion improves readiness without fatigue."],"coach_cues":["Rotate from the ground up.","Ribs and pelvis travel as a team.","Own the finish before the next rep.","Open range without forcing it.","Smooth first, then crisp."],"common_faults":["Low back becomes the main rotation point.","Feet lose pressure or the athlete spins on the toes without a controlled base.","Ribs flare, shoulders shrug, or pelvis dumps forward during the turn."],"breathing_cues":["Exhale through effort or release.","Do not hold breath to force rotation.","Recover breathing before the next high-intent rep."],"quality_gate":"The rep counts only if the athlete keeps foot pressure, rib-pelvis organization, clean rotational path, safe finish, and a reset that could be repeated.","stop_signs":["Sharp pain, joint pinch, numbness, tingling, dizziness, or symptom increase.","Lumbar spine becomes the main source of rotation instead of hips, pelvis, thoracic spine, and shoulders.","The athlete loses foot pressure, trunk stack, safe landing, throw accuracy, or controlled reset."]}'::jsonb),
  ('Spiderman Lunge with T-Spine Reach', 'spiderman-lunge-with-t-spine-reach', 'Perform Spiderman Lunge with T-Spine Reach slowly enough to create usable rotational access and coordination. Move through pain-free range, breathe, and own the position before adding speed or load.', 'BEGINNER', 8, 2, 6, 25, 20, 45, 'Spiderman Lunge with T-Spine Reach is a Prepare & Access exercise for hip opening plus thoracic reach. Use it when the goal is rotational skill, force transfer, or power quality rather than fatigue chasing.', 'Primary subrole: mobilize. Coach Spiderman Lunge with T-Spine Reach as rotational-athlete work: rotation should be organized through feet, hips, pelvis, thoracic spine, shoulders, and the implement or direction change - not forced through the low back.', 'Open the range, feel the turn, and do not force your low back.', 'Lunge rotation mobility', 'prepare_and_access', 'mobilize', 'spiderman_lunge_t_spine_reach', '{"primary_joint_actions":["hip rotation","hip/knee flexion-extension","thoracic rotation","trunk bracing"],"primary_tissues":["ankle","hip","shoulder","spine"],"breathing_demand":"low_to_moderate","balance_demand":"moderate","coordination_demand":"moderate_to_high","impact_level":0,"rotational_power_profile":{"rotation_source":"feet, hips, pelvis, thoracic spine, and shoulders; avoid forced lumbar twisting","sequence_priority":"load or gather, brace, rotate, transfer, finish, and reset","quality_rule":"The rep counts only if the athlete keeps foot pressure, rib-pelvis organization, clean rotational path, safe finish, and a reset that could be repeated."}}'::jsonb, '{"movement_description":"Perform Spiderman Lunge with T-Spine Reach slowly enough to create usable rotational access and coordination. Move through pain-free range, breathe, and own the position before adding speed or load.","setup":["Clear the training area and define the athlete''s start position, finish position, and stop command.","Coach one clean practice rep before adding load, speed, partner input, or decision demand."],"execution_steps":["Move into the starting position slowly and find the target joint or stance position.","Rotate, reach, shift, or step through pain-free range while breathing naturally.","Return with control and repeat only as long as the motion improves readiness without fatigue."],"coach_cues":["Rotate from the ground up.","Ribs and pelvis travel as a team.","Own the finish before the next rep.","Open range without forcing it.","Smooth first, then crisp."],"common_faults":["Low back becomes the main rotation point.","Feet lose pressure or the athlete spins on the toes without a controlled base.","Ribs flare, shoulders shrug, or pelvis dumps forward during the turn."],"breathing_cues":["Exhale through effort or release.","Do not hold breath to force rotation.","Recover breathing before the next high-intent rep."],"quality_gate":"The rep counts only if the athlete keeps foot pressure, rib-pelvis organization, clean rotational path, safe finish, and a reset that could be repeated.","stop_signs":["Sharp pain, joint pinch, numbness, tingling, dizziness, or symptom increase.","Lumbar spine becomes the main source of rotation instead of hips, pelvis, thoracic spine, and shoulders.","The athlete loses foot pressure, trunk stack, safe landing, throw accuracy, or controlled reset."]}'::jsonb),
  ('Standing Hip-Shoulder Separation Drill', 'standing-hip-shoulder-separation-drill', 'Perform Standing Hip-Shoulder Separation Drill slowly enough to create usable rotational access and coordination. Move through pain-free range, breathe, and own the position before adding speed or load.', 'BEGINNER', 8, 2, 5, 20, 30, 50, 'Standing Hip-Shoulder Separation Drill is a Movement Intelligence exercise for pelvis and ribcage dissociation. Use it when the goal is rotational skill, force transfer, or power quality rather than fatigue chasing.', 'Primary subrole: coordinate. Coach Standing Hip-Shoulder Separation Drill as rotational-athlete work: rotation should be organized through feet, hips, pelvis, thoracic spine, shoulders, and the implement or direction change - not forced through the low back.', 'Open the range, feel the turn, and do not force your low back.', 'Rotational sequencing primer', 'movement_intelligence', 'coordinate', 'standing_hip_shoulder_separation', '{"primary_joint_actions":["hip rotation","thoracic rotation","trunk bracing"],"primary_tissues":["core","hip","shoulder","spine"],"breathing_demand":"low_to_moderate","balance_demand":"moderate_to_high","coordination_demand":"high","impact_level":1,"rotational_power_profile":{"rotation_source":"feet, hips, pelvis, thoracic spine, and shoulders; avoid forced lumbar twisting","sequence_priority":"load or gather, brace, rotate, transfer, finish, and reset","quality_rule":"The rep counts only if the athlete keeps foot pressure, rib-pelvis organization, clean rotational path, safe finish, and a reset that could be repeated."}}'::jsonb, '{"movement_description":"Perform Standing Hip-Shoulder Separation Drill slowly enough to create usable rotational access and coordination. Move through pain-free range, breathe, and own the position before adding speed or load.","setup":["Clear the training area and define the athlete''s start position, finish position, and stop command.","Coach one clean practice rep before adding load, speed, partner input, or decision demand."],"execution_steps":["Move into the starting position slowly and find the target joint or stance position.","Rotate, reach, shift, or step through pain-free range while breathing naturally.","Return with control and repeat only as long as the motion improves readiness without fatigue."],"coach_cues":["Rotate from the ground up.","Ribs and pelvis travel as a team.","Own the finish before the next rep.","Open range without forcing it.","Smooth first, then crisp."],"common_faults":["Low back becomes the main rotation point.","Feet lose pressure or the athlete spins on the toes without a controlled base.","Ribs flare, shoulders shrug, or pelvis dumps forward during the turn."],"breathing_cues":["Exhale through effort or release.","Do not hold breath to force rotation.","Recover breathing before the next high-intent rep."],"quality_gate":"The rep counts only if the athlete keeps foot pressure, rib-pelvis organization, clean rotational path, safe finish, and a reset that could be repeated.","stop_signs":["Sharp pain, joint pinch, numbness, tingling, dizziness, or symptom increase.","Lumbar spine becomes the main source of rotation instead of hips, pelvis, thoracic spine, and shoulders.","The athlete loses foot pressure, trunk stack, safe landing, throw accuracy, or controlled reset."]}'::jsonb),
  ('Wall Split-Stance Rotation Reach', 'wall-split-stance-rotation-reach', 'Perform Wall Split-Stance Rotation Reach slowly enough to create usable rotational access and coordination. Move through pain-free range, breathe, and own the position before adding speed or load.', 'BEGINNER', 8, 2, 6, 25, 20, 45, 'Wall Split-Stance Rotation Reach is a Prepare & Access exercise for split-stance rotation and front-leg brace. Use it when the goal is rotational skill, force transfer, or power quality rather than fatigue chasing.', 'Primary subrole: mobilize. Coach Wall Split-Stance Rotation Reach as rotational-athlete work: rotation should be organized through feet, hips, pelvis, thoracic spine, shoulders, and the implement or direction change - not forced through the low back.', 'Open the range, feel the turn, and do not force your low back.', 'Split-stance rotation access', 'prepare_and_access', 'mobilize', 'wall_split_stance_rotation_reach', '{"primary_joint_actions":["hip rotation","hip/knee flexion-extension","thoracic rotation","trunk bracing"],"primary_tissues":["core","hip","shoulder","spine"],"breathing_demand":"low_to_moderate","balance_demand":"moderate","coordination_demand":"moderate_to_high","impact_level":0,"rotational_power_profile":{"rotation_source":"feet, hips, pelvis, thoracic spine, and shoulders; avoid forced lumbar twisting","sequence_priority":"load or gather, brace, rotate, transfer, finish, and reset","quality_rule":"The rep counts only if the athlete keeps foot pressure, rib-pelvis organization, clean rotational path, safe finish, and a reset that could be repeated."}}'::jsonb, '{"movement_description":"Perform Wall Split-Stance Rotation Reach slowly enough to create usable rotational access and coordination. Move through pain-free range, breathe, and own the position before adding speed or load.","setup":["Clear the training area and define the athlete''s start position, finish position, and stop command.","Coach one clean practice rep before adding