INSERT INTO coaching.exercise_phase_profile (
  exercise_id, phase_id, fit_weight, role, order_slot, order_index,
  freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling
)
SELECT e.id, sp.id, COALESCE(m.fit_weight, 5), 'primary', m.slot, pos.order_index,
  COALESCE(m.freshness_required, FALSE), COALESCE(m.fatigue_sensitivity, 2), COALESCE(m.fatigue_cost, 2),
  COALESCE(m.technical_complexity, 2), COALESCE(m.impact_level, 1), COALESCE(m.intensity_ceiling, 'moderate')
FROM (VALUES
  ('half-kneeling-t-spine-rotation', 'prepare_and_access', 'half_kneeling_t_spine_rotation_access', 5, FALSE, 1, 1, 2, 0, 'low'),
  ('spiderman-lunge-with-t-spine-reach', 'prepare_and_access', 'spiderman_lunge_t_spine_reach', 5, FALSE, 1, 1, 2, 0, 'low'),
  ('standing-hip-shoulder-separation-drill', 'movement_intelligence', 'standing_hip_shoulder_separation', 5, TRUE, 4, 2, 4, 1, 'low_to_moderate'),
  ('wall-split-stance-rotation-reach', 'prepare_and_access', 'wall_split_stance_rotation_reach', 5, FALSE, 1, 1, 2, 0, 'low'),
  ('quadruped-thread-the-needle-reach', 'prepare_and_access', 'quadruped_thread_the_needle_reach', 5, FALSE, 1, 1, 2, 0, 'low'),
