  ('landmine-rotation', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('split-stance-cable-chop', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('rotational-cable-row', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('cable-shot-put-press', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('lateral-lunge-to-rotational-reach', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
  ('suitcase-carry-with-direction-change', FALSE, 3, 24, FALSE, FALSE, FALSE, TRUE, FALSE),
