  ('med-ball-shuffle-to-rotation-throw', FALSE, 3, 24, TRUE, FALSE, TRUE, TRUE, FALSE),
  ('med-ball-countermovement-rotational-throw', FALSE, 3, 24, TRUE, FALSE, TRUE, TRUE, FALSE),
